#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int N;
    scanf("%d", &N);
    int* A = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    long long** dp = (long long**)malloc(N * sizeof(long long*));
    for (int i = 0; i < N; i++) {
        dp[i] = (long long*)malloc(N * sizeof(long long));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < N; i++) {
        if (A[i] < 0) {
            dp[i][0] = 1;
        }
    }
    for (int i = 1; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (A[i] < 0) {
                dp[i][j] = dp[i - 1][j];
            } else {
                dp[i][j] = dp[i - 1][j];
                if (j > 0) {
                    dp[i][j] += dp[i - 1][j - 1];
                    dp[i][j] %= MOD;
                }
            }
        }
    }
    long long ans = 0;
    for (int i = 0; i < N; i++) {
        ans += dp[N - 1][i];
        ans %= MOD;
    }
    printf("%lld\n", ans);
    return 0;
}

